    "path": "Borderlands3Trainer/Program.cs",
    "content": "using System;\nusing System.Threading;\nusing Borderlands3Trainer.Core;\n\nnamespace Borderlands3Trainer\n{\n    /// <summary>\n    /// Entry point for the Borderlands 3 Trainer application.\n    /// Provides a console-based interface to activate various cheats via memory manipulation.\n    /// </summary>\n    internal class Program\n    {\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Borderlands 3 Trainer v1.0\");\n            Console.WriteLine(\"==========================\");\n            Console.WriteLine(\"Ensure Borderlands 3 is running before using commands.\");\n            Console.WriteLine(\"Commands: god, ammo, money, speed, exit\");\n\n            var memoryManager = new MemoryManager(\"Borderlands3\");\n            var cheatEngine = new CheatEngine(memoryManager);\n\n            while (true)\n            {\n                Console.Write(\"\\nEnter command: \");\n                var input = Console.ReadLine()?.Trim().ToLowerInvariant();\n\n                switch (input)\n                {\n                    case \"god\":\n                        cheatEngine.ToggleGodMode();\n                        Console.WriteLine(\"God mode toggled.\");\n                        break;\n                    case \"ammo\":\n                        cheatEngine.SetInfiniteAmmo(true);\n                        Console.WriteLine(\"Infinite ammo enabled.\");\n                        break;\n                    case \"money\":\n                        cheatEngine.AddMoney(999999);\n                        Console.WriteLine(\"Added 999999 money.\");\n                        break;\n                    case \"speed\":\n                        cheatEngine.SetSpeedMultiplier(2.0f);\n                        Console.WriteLine(\"Speed multiplier set to 2.0.\");\n                        break;\n                    case \"exit\":\n                        Console.WriteLine(\"Exiting...\");\n                        return;\n                    default:\n                        Console.WriteLine(\"Unknown command. Available: god, ammo, money, speed, exit\");\n                        break;\n                }\n\n                // Brief pause to prevent command spam\n                Thread.Sleep(100);\n            }\n        }\n    }\n}\n"
  },
