    "path": "Borderlands3Trainer/Core/MemoryManager.cs",
    "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace Borderlands3Trainer.Core\n{\n    /// <summary>\n    /// Manages low-level memory operations for the Borderlands 3 process.\n    /// Uses Windows API calls to read/write process memory.\n    /// </summary>\n    public class MemoryManager : IDisposable\n    {\n        private readonly IntPtr _processHandle;\n        private readonly int _processId;\n        private bool _disposed;\n\n        // Windows API imports\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        private const uint PROCESS_ALL_ACCESS = 0x1F0FFF;\n\n        /// <summary>\n        /// Initializes a new instance of the MemoryManager class.\n        /// </summary>\n        /// <param name=\"processName\">Name of the target process (e.g., \"Borderlands3\").</param>\n        public MemoryManager(string processName)\n        {\n            var processes = Process.GetProcessesByName(processName);\n            if (processes.Length == 0)\n                throw new InvalidOperationException($\"Process '{processName}' not found. Make sure Borderlands 3 is running.\");\n\n            var targetProcess = processes[0];\n            _processId = targetProcess.Id;\n            _processHandle = OpenProcess(PROCESS_ALL_ACCESS, false, _processId);\n\n            if (_processHandle == IntPtr.Zero)\n                throw new InvalidOperationException(\"Failed to open process handle. Run as administrator.\");\n        }\n\n        /// <summary>\n        /// Reads a block of memory from the target process.\n        /// </summary>\n        /// <param name=\"address\">Memory address to read from.</param>\n        /// <param name=\"size\">Number of bytes to read.</param>\n        /// <returns>Byte array containing the read data.</returns>\n        public byte[] ReadMemory(IntPtr address, int size)\n        {\n            var buffer = new byte[size];\n            if (!ReadProcessMemory(_processHandle, address, buffer, size, out int bytesRead))\n                throw new InvalidOperationException($\"Failed to read memory at 0x{address.ToInt64():X}. Error code: {Marshal.GetLastWin32Error()}\");\n\n            if (bytesRead != size)\n                throw new InvalidOperationException($\"Read {bytesRead} bytes, expected {size}.\");\n\n            return buffer;\n        }\n\n        /// <summary>\n        /// Writes a block of memory to the target process.\n        /// </summary>\n        /// <param name=\"address\">Memory address to write to.</param>\n        /// <param name=\"data\">Byte array containing data to write.</param>\n        public void WriteMemory(IntPtr address, byte[] data)\n        {\n            if (!WriteProcessMemory(_processHandle, address, data, data.Length, out int bytesWritten))\n                throw new InvalidOperationException($\"Failed to write memory at 0x{address.ToInt64():X}. Error code: {Marshal.GetLastWin32Error()}\");\n\n            if (bytesWritten != data.Length)\n                throw new InvalidOperationException($\"Wrote {bytesWritten} bytes, expected {data.Length}.\");\n        }\n\n        /// <summary>\n        /// Reads a 4-byte integer from the target process.\n        /// </summary>\n        /// <param name=\"address\">Memory address to read from.</param>\n        /// <returns>Integer value at the address.</returns>\n        public int ReadInt32(IntPtr address)\n        {\n            var data = ReadMemory(address, 4);\n            return BitConverter.ToInt32(data, 0);\n        }\n\n        /// <summary>\n        /// Writes a 4-byte integer to the target process.\n        /// </summary>\n        /// <param name=\"address\">Memory address to write to.</param>\n        /// <param name=\"value\">Integer value to write.</param>\n        public void WriteInt32(IntPtr address, int value)\n        {\n            var data = BitConverter.GetBytes(value);\n            WriteMemory(address, data);\n        }\n\n        /// <summary>\n        /// Reads a 4-byte float from the target process.\n        /// </summary>\n        /// <param name=\"address\">Memory address to read from.</param>\n        /// <returns>Float value at the address.</returns>\n        public float ReadFloat(IntPtr address)\n        {\n            var data = ReadMemory(address, 4);\n            return BitConverter.ToSingle(data, 0);\n        }\n\n        /// <summary>\n        /// Writes a 4-byte float to the target process.\n        /// </summary>\n        /// <param name=\"address\">Memory address to write to.</param>\n        /// <param name=\"value\">Float value to write.</param>\n        public void WriteFloat(IntPtr address, float value)\n        {\n            var data = BitConverter.GetBytes(value);\n            WriteMemory(address, data);\n        }\n\n        /// <summary>\n        /// Disposes the process handle.\n        /// </summary>\n        public void Dispose()\n        {\n            if (!_disposed && _processHandle != IntPtr.Zero)\n            {\n                CloseHandle(_processHandle);\n                _disposed = true;\n            }\n        }\n    }\n}\n"
