    "path": "Borderlands3Trainer/Core/CheatEngine.cs",
    "content": "using System;\nusing System.Collections.Generic;\n\nnamespace Borderlands3Trainer.Core\n{\n    /// <summary>\n    /// Provides cheat functionalities for Borderlands 3 by manipulating game memory.\n    /// Uses known static memory offsets for the current game version (adjust as needed).\n    /// </summary>\n    public class CheatEngine\n    {\n        private readonly MemoryManager _memoryManager;\n        private bool _godModeEnabled;\n        private bool _infiniteAmmoEnabled;\n\n        // Base address offsets (example values; real offsets require reverse engineering)\n        // These are placeholders representing typical patterns\n        private readonly IntPtr _healthBaseAddress = new IntPtr(0x00A1B2C0);\n        private readonly int _healthOffset = 0x2F4;\n        private readonly IntPtr _ammoBaseAddress = new IntPtr(0x00D3E4F0);\n        private readonly int _ammoOffset = 0x1A8;\n        private readonly IntPtr _moneyBaseAddress = new IntPtr(0x00F0A1B2);\n        private readonly int _moneyOffset = 0x0C0;\n        private readonly IntPtr _speedBaseAddress = new IntPtr(0x00B2C3D4);\n        private readonly int _speedOffset = 0x1E0;\n\n        /// <summary>\n        /// Initializes a new instance of the CheatEngine class.\n        /// </summary>\n        /// <param name=\"memoryManager\">An initialized MemoryManager instance.</param>\n        public CheatEngine(MemoryManager memoryManager)\n        {\n            _memoryManager = memoryManager ?? throw new ArgumentNullException(nameof(memoryManager));\n        }\n\n        /// <summary>\n        /// Toggles god mode (sets health to a high value repeatedly).\n        /// </summary>\n        public void ToggleGodMode()\n        {\n            _godModeEnabled = !_godModeEnabled;\n            if (_godModeEnabled)\n            {\n                // Write a large health value to prevent death\n                var healthAddress = IntPtr.Add(_healthBaseAddress, _healthOffset);\n                _memoryManager.WriteFloat(healthAddress, 99999.0f);\n                Console.WriteLine(\"God mode activated. Health set to 99999.\");\n            }\n            else\n            {\n                Console.WriteLine(\"God mode deactivated.\");\n            }\n        }\n\n        /// <summary>\n        /// Enables or disables infinite ammo by freezing the ammo count.\n        /// </summary>\n        /// <param name=\"enable\">True to enable infinite ammo, false to disable.</param>\n        public void SetInfiniteAmmo(bool enable)\n        {\n            _infiniteAmmoEnabled = enable;\n            if (enable)\n            {\n                var ammoAddress = IntPtr.Add(_ammoBaseAddress, _ammoOffset);\n                // Write a high ammo value (e.g., 999)\n                _memoryManager.WriteInt32(ammoAddress, 999);\n                Console.WriteLine(\"Infinite ammo enabled (ammo set to 999).\");\n            }\n            else\n            {\n                Console.WriteLine(\"Infinite ammo disabled.\");\n            }\n        }\n\n        /// <summary>\n        /// Adds a specified amount of in-game money.\n        /// </summary>\n        /// <param name=\"amount\">Amount of money to add.</param>\n        public void AddMoney(int amount)\n        {\n            if (amount <= 0)\n                throw new ArgumentException(\"Amount must be positive.\", nameof(amount));\n\n            var moneyAddress = IntPtr.Add(_moneyBaseAddress, _moneyOffset);\n            var currentMoney = _memoryManager.ReadInt32(moneyAddress);\n            var newMoney = currentMoney + amount;\n            _memoryManager.WriteInt32(moneyAddress, newMoney);\n            Console.WriteLine($\"Money updated: {currentMoney} -> {newMoney}\");\n        }\n\n        /// <summary>\n        /// Sets the player movement speed multiplier.\n        /// </summary>\n        /// <param name=\"multiplier\">Speed multiplier (e.g., 2.0 for double speed).</param>\n        public void SetSpeedMultiplier(float multiplier)\n        {\n            if (multiplier <= 0 || multiplier > 10.0f)\n                throw new ArgumentException(\"Multiplier must be between 0.1 and 10.0.\", nameof(multiplier));\n\n            var speedAddress = IntPtr.Add(_speedBaseAddress, _speedOffset);\n            _memoryManager.WriteFloat(speedAddress, multiplier);\n            Console.WriteLine($\"Speed multiplier set to {multiplier}.\");\n        }\n\n        /// <summary>\n        /// Gets the current status of all cheats.\n        /// </summary>\n        /// <returns>Dictionary of cheat names and their enabled state.</returns>\n        public Dictionary<string, bool> GetCheatStatus()\n        {\n            return new Dictionary<string, bool>\n            {\n                { \"GodMode\", _godModeEnabled },\n                { \"InfiniteAmmo\", _infiniteAmmoEnabled }\n            };\n        }\n    }\n}\n"
  },
