    "path": "tests/Borderlands3Trainer.Tests/CheatEngineTests.cs",
    "content": "using System;\nusing Borderlands3Trainer.Core;\nusing Moq;\nusing Xunit;\n\nnamespace Borderlands3Trainer.Tests\n{\n    /// <summary>\n    /// Unit tests for the CheatEngine class, using a mocked MemoryManager.\n    /// </summary>\n    public class CheatEngineTests\n    {\n        [Fact]\n        public void AddMoney_WithPositiveAmount_IncreasesMoney()\n        {\n            // Arrange\n            var mockMemoryManager = new Mock<MemoryManager>(\"Borderlands3\");\n            // Simulate current money value of 1000\n            mockMemoryManager.Setup(m => m.ReadInt32(It.IsAny<IntPtr>())).Returns(1000);\n            var cheatEngine = new CheatEngine(mockMemoryManager.Object);\n\n            // Act\n            cheatEngine.AddMoney(500);\n\n            // Assert\n            mockMemoryManager.Verify(m => m.WriteInt32(It.IsAny<IntPtr>(), 1500), Times.Once);\n        }\n\n        [Fact]\n        public void AddMoney_WithNegativeAmount_ThrowsArgumentException()\n        {\n            // Arrange\n            var mockMemoryManager = new Mock<MemoryManager>(\"Borderlands3\");\n            var cheatEngine = new CheatEngine(mockMemoryManager.Object);\n\n            // Act & Assert\n            Assert.
